#include <stdio.h>

int main() {
    int N;
    if (scanf("%d", &N) != 1) return 0;
    while (N--) {
        long long i, j;
        scanf("%lld %lld", &i, &j);
        int dist = 0;
        while (i != j) {
            if (i > j) i >>= 1; else j >>= 1;
            ++dist;
        }
        printf("%d\n", dist);
    }
    return 0;
}

