#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    out = []
    for _ in range(N):
        i = int(next(it)); j = int(next(it))
        dist = 0
        while i != j:
            if i > j:
                i >>= 1
            else:
                j >>= 1
            dist += 1
        out.append(str(dist))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

